const express = require('express');
const jwt = require('jsonwebtoken');
const jwksRsa = require('jwks-rsa');
const crypto = require('crypto');

const app = express();
app.use(express.json());

// Configuration - set via environment variables
const config = {
  port: process.env.PORT || 3000,
  issuer: process.env.OAUTH_ISSUER || 'https://auth.example.com',
  audience: process.env.OAUTH_AUDIENCE || 'https://api.example.com',
  jwksUri: process.env.JWKS_URI || 'https://auth.example.com/.well-known/jwks.json',
  // For symmetric signing (HS256) - use either JWKS or this, not both
  jwtSecret: process.env.JWT_SECRET || null,
  // Algorithm preference
  algorithms: (process.env.JWT_ALGORITHMS || 'RS256').split(','),
};

// JWKS client for fetching public keys (RS256, ES256, etc.)
const jwksClient = jwksRsa({
  jwksUri: config.jwksUri,
  cache: true,
  cacheMaxEntries: 5,
  cacheMaxAge: 600000, // 10 minutes
  rateLimit: true,
  jwksRequestsPerMinute: 10,
});

// Key retrieval function for asymmetric algorithms
function getSigningKey(header, callback) {
  jwksClient.getSigningKey(header.kid, (err, key) => {
    if (err) {
      return callback(err);
    }
    const signingKey = key.getPublicKey();
    callback(null, signingKey);
  });
}

// Extract bearer token from Authorization header
function extractBearerToken(req) {
  const authHeader = req.headers.authorization;
  if (!authHeader) {
    return null;
  }

  const parts = authHeader.split(' ');
  if (parts.length !== 2 || parts[0].toLowerCase() !== 'bearer') {
    return null;
  }

  return parts[1];
}

// Verify JWT token
function verifyToken(token) {
  return new Promise((resolve, reject) => {
    const verifyOptions = {
      algorithms: config.algorithms,
      issuer: config.issuer,
      audience: config.audience,
      clockTolerance: 30, // 30 seconds clock skew tolerance
    };

    // Determine if we use symmetric or asymmetric verification
    const isSymmetric = config.algorithms.some(alg => alg.startsWith('HS'));

    if (isSymmetric && config.jwtSecret) {
      jwt.verify(token, config.jwtSecret, verifyOptions, (err, decoded) => {
        if (err) return reject(err);
        resolve(decoded);
      });
    } else {
      // Use JWKS for asymmetric key retrieval
      jwt.verify(token, getSigningKey, verifyOptions, (err, decoded) => {
        if (err) return reject(err);
        resolve(decoded);
      });
    }
  });
}

// Authentication middleware
async function authenticate(req, res, next) {
  const token = extractBearerToken(req);

  if (!token) {
    return res.status(401).json({
      error: 'unauthorized',
      error_description: 'Missing or malformed Authorization header. Expected: Bearer <token>',
    });
  }

  try {
    const decoded = await verifyToken(token);

    // Attach decoded token claims to the request
    req.auth = {
      sub: decoded.sub,
      iss: decoded.iss,
      aud: decoded.aud,
      exp: decoded.exp,
      iat: decoded.iat,
      scope: decoded.scope || decoded.scp || '',
      claims: decoded,
    };

    // Parse scopes into an array for easier checking
    if (typeof req.auth.scope === 'string') {
      req.auth.scopes = req.auth.scope.split(' ').filter(Boolean);
    } else if (Array.isArray(req.auth.scope)) {
      req.auth.scopes = req.auth.scope;
    } else {
      req.auth.scopes = [];
    }

    next();
  } catch (err) {
    let statusCode = 401;
    let errorDescription = 'Invalid access token';

    if (err.name === 'TokenExpiredError') {
      errorDescription = 'Access token has expired';
    } else if (err.name === 'JsonWebTokenError') {
      errorDescription = `Token verification failed: ${err.message}`;
    } else if (err.name === 'NotBeforeError') {
      errorDescription = 'Token is not yet valid';
    }

    console.error(`[AUTH] Token validation failed: ${err.message}`, {
      error: err.name,
      timestamp: new Date().toISOString(),
      requestId: req.headers['x-request-id'] || 'unknown',
    });

    return res.status(statusCode).json({
      error: 'invalid_token',
      error_description: errorDescription,
    });
  }
}

// Scope-checking middleware factory
function requireScope(...requiredScopes) {
  return (req, res, next) => {
    if (!req.auth) {
      return res.status(401).json({
        error: 'unauthorized',
        error_description: 'Authentication required',
      });
    }

    const hasAllScopes = requiredScopes.every(scope => req.auth.scopes.includes(scope));

    if (!hasAllScopes) {
      return res.status(403).json({
        error: 'insufficient_scope',
        error_description: `Required scopes: ${requiredScopes.join(', ')}`,
        required_scopes: requiredScopes,
        granted_scopes: req.auth.scopes,
      });
    }

    next();
  };
}

// Middleware to require any one of the specified scopes
function requireAnyScope(...requiredScopes) {
  return (req, res, next) => {
    if (!req.auth) {
      return res.status(401).json({
        error: 'unauthorized',
        error_description: 'Authentication required',
      });
    }

    const hasAnyScope = requiredScopes.some(scope => req.auth.scopes.includes(scope));

    if (!hasAnyScope) {
      return res.status(403).json({
        error: 'insufficient_scope',
        error_description: `At least one of these scopes is required: ${requiredScopes.join(', ')}`,
        required_scopes: requiredScopes,
        granted_scopes: req.auth.scopes,
      });
    }

    next();
  };
}

